 27→// Shared flag so API failures can signal the adapter to re-check daemon
 28→let _daemonEnsuredFlag = true
 29→// Last project dir we ensured daemon for — reset flag on project switch
 30→let _daemonEnsuredForCwd: string | null = null
 31→
 32→async function api<T>(method: string, path: string, cwd: string, body?: unknown): Promise<T> {
 33→  const opts: RequestInit = {
 34→    method,
 35→    headers: headers(cwd)
 36→  }
 37→  if (body) opts.body = JSON.stringify(body)
 38→  let res: Response
 39→  try {
 40→    res = await fetch(`${API_BASE}${path}`, opts)
 41→  } catch (e) {
 42→    // Network error — daemon likely crashed, reset ensured flag
 43→    _daemonEnsuredFlag = false
 44→    throw e
 45→  }
 46→  if (!res.ok) {
 47→    const text = await res.text()
 48→    throw new Error(text || `HTTP ${res.status}`)
 49→  }
 50→  return res.json()
 51→}
 52→
 53→function normalizeStatus(status: string): TaskStatus {
 54→  switch (status) {
 55→    case 'in_progress': return 'in_progress'
 56→    case 'completed':
 57→    case 'cancelled':
 58→      return 'closed'
 59→    case 'pending':
 60→    case 'blocked':
 61→    case 'pending_review':
 62→    case 'needs_work':
 63→    default:
 64→      return 'open'
 65→  }
 66→}
 67→
 68→function toUnified(raw: Record<string, unknown>): UnifiedTask {
 69→  const tags = Array.isArray(raw.tags) ? raw.tags.map(String) : undefined
 70→  // kspec uses _ulid as primary ID and slugs[] for human-friendly refs
 71→  const slugs = Array.isArray(raw.slugs) ? raw.slugs : []
 72→  // Use slug if available, otherwise full ULID (needed for API calls)
 73→  const id = slugs.length > 0 ? String(slugs[0]) : String(raw._ulid ?? raw.slug ?? raw.id ?? '')
 74→  return {
 75→    id,
 76→    // Short display ID for the UI — slug or first 8 chars of ULID
 77→    displayId: slugs.length > 0 ? String(slugs[0]) : (id.length > 12 ? id.slice(0, 8) : id),
 78→    title: String(raw.title ?? ''),
 79→    status: normalizeStatus(String(raw.status ?? 'pending')),
 80→    priority: typeof raw.priority === 'number' ? raw.priority : undefined,
 81→    type: typeof raw.type === 'string' ? raw.type : undefined,
 82→    description: typeof raw.description === 'string' ? raw.description : undefined,
 83→    created_at: typeof raw.created_at === 'string' ? raw.created_at : undefined,
 84→    updated_at: typeof raw.updated_at === 'string' ? raw.updated_at : undefined,
 85→    tags,
 86→    automation: typeof raw.automation === 'string' ? raw.automation as UnifiedTask['automation'] : undefined,
 87→    _backend: 'kspec'
 88→  }
 89→}
