 93→
 94→  private async ensureDaemon(cwd: string): Promise<boolean> {
 95→    // Reset flag when switching projects so we re-verify daemon for new cwd
 96→    if (_daemonEnsuredForCwd !== null && _daemonEnsuredForCwd !== cwd) {
 97→      _daemonEnsuredFlag = false
 98→    }
