112→  async check(cwd: string): Promise<BackendStatus> {
113→    // Check if .kspec/ exists via IPC (filesystem check)
114→    const hasKspec = await window.electronAPI?.kspecCheck?.(cwd)
115→    if (!hasKspec?.exists) {
116→      return { kind: 'kspec', installed: true, initialized: false }
117→    }
118→
119→    // Try to ensure daemon is running
120→    await this.ensureDaemon(cwd)
121→    return { kind: 'kspec', installed: true, initialized: true }
122→  }
123→
124→  async init(cwd: string): Promise<{ success: boolean; error?: string }> {
125→    const result = await window.electronAPI?.kspecInit?.(cwd)
126→    return { success: !!result?.success, error: result?.error }
127→  }
128→
129→  async list(cwd: string): Promise<UnifiedTask[]> {
130→    try {
131→      const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd)
132→      return (data.items ?? []).map(toUnified)
133→    } catch {
134→      // Daemon might not be running — try to start it and retry once
135→      const started = await this.ensureDaemon(cwd)
136→      if (started) {
137→        try {
138→          const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd)
139→          return (data.items ?? []).map(toUnified)
140→        } catch { /* still failed */ }
141→      }
142→      return []
143→    }
144→  }
145→
146→  async show(cwd: string, taskId: string): Promise<UnifiedTask | null> {
147→    try {
148→      const data = await api<Record<string, unknown>>('GET', `/api/tasks/${encodeURIComponent(taskId)}`, cwd)
149→      return toUnified(data)
150→    } catch {
151→      return null
152→    }
153→  }
154→
155→  async create(cwd: string, params: CreateTaskParams): Promise<{ success: boolean; error?: string }> {
156→    try {
157→      await api('POST', '/api/tasks', cwd, {
158→        title: params.title,
159→        description: params.description,
160→        priority: params.priority,
161→        type: params.type,
162→        tags: params.tags?.split(',').map(t => t.trim()).filter(Boolean),
163→        automation: params.automation || undefined
164→      })
165→      return { success: true }
166→    } catch (e) {
167→      return { success: false, error: String(e) }
168→    }
169→  }
170→
171→  async start(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
172→    try {
173→      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/start`, cwd)
174→      return { success: true }
175→    } catch (e) {
176→      return { success: false, error: String(e) }
177→    }
178→  }
179→
180→  async complete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
181→    try {
182→      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/complete`, cwd)
183→      return { success: true }
184→    } catch (e) {
185→      return { success: false, error: String(e) }
186→    }
187→  }
188→
189→  async delete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
190→    try {
191→      await api('DELETE', `/api/tasks/${encodeURIComponent(taskId)}`, cwd)
192→      return { success: true }
193→    } catch (e) {
194→      return { success: false, error: String(e) }
195→    }
196→  }
197→
198→  async update(cwd: string, taskId: string, params: UpdateTaskParams): Promise<{ success: boolean; error?: string }> {
199→    try {
200→      // Map unified status names back to kspec native status names
201→      const body = { ...params }
202→      if (body.status === 'open') body.status = 'pending' as TaskStatus
203→      if (body.status === 'closed') body.status = 'completed' as TaskStatus
204→      await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, body)
205→      return { success: true }
206→    } catch (e) {
207→      return { success: false, error: String(e) }
208→    }
209→  }
210→
211→  async cycleStatus(cwd: string, taskId: string, currentStatus: TaskStatus): Promise<{ success: boolean; error?: string }> {
212→    switch (currentStatus) {
213→      case 'open': return this.start(cwd, taskId)
214→      case 'in_progress': return this.complete(cwd, taskId)
215→      default:
216→        // Kspec uses 'pending' internally — 'open' is only the unified status
217→        try {
218→          await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, { status: 'pending' })
219→          return { success: true }
220→        } catch (e) {
221→          return { success: false, error: String(e) }
222→        }
223→    }
224→  }
225→
226→  // Kspec uses WebSocket for live updates instead of file watching
227→  private ws: WebSocket | null = null
228→  private wsCallbacks: Set<(data: { cwd: string }) => void> = new Set()
229→  private watchedCwd: string | null = null
230→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null
231→  private reconnectDelay = 1000
232→  private watching = false
233→
234→  watch(cwd: string): void {
235→    // If switching projects, close old connection first
236→    if (this.ws && this.watchedCwd !== cwd) {
237→      this.ws.close()
238→      this.ws = null
239→    }
240→    this.watching = true
241→    this.watchedCwd = cwd
242→    this.reconnectDelay = 1000
243→    this.connectWs(cwd)
244→  }
245→
246→  private connectWs(cwd: string): void {
247→    if (this.ws) return
248→    try {
249→      this.ws = new WebSocket(`ws://localhost:${DAEMON_PORT}/ws?project=${encodeURIComponent(cwd)}`)
250→      this.ws.onmessage = (event) => {
251→        try {
252→          const msg = JSON.parse(event.data)
253→          if (msg.event === 'tasks:updates' || msg.event === 'task_updated') {
254→            this.wsCallbacks.forEach(cb => cb({ cwd }))
255→          }
256→        } catch { /* ignore parse errors */ }
257→      }
258→      this.ws.onopen = () => {
259→        this.reconnectDelay = 1000 // Reset backoff on successful connection
260→      }
261→      this.ws.onclose = () => {
262→        this.ws = null
263→        // Auto-reconnect with exponential backoff (cap at 30s)
264→        if (this.watching && this.watchedCwd === cwd) {
265→          this.reconnectTimer = setTimeout(() => this.connectWs(cwd), this.reconnectDelay)
266→          this.reconnectDelay = Math.min(this.reconnectDelay * 2, 30000)
267→        }
268→      }
269→      this.ws.onerror = () => {
270→        // onclose will fire after onerror, triggering reconnect
271→      }
272→    } catch { /* daemon not running — reconnect will retry */ }
273→  }
274→
275→  unwatch(_cwd: string): void {
276→    this.watching = false
277→    this.watchedCwd = null
278→    if (this.reconnectTimer) {
279→      clearTimeout(this.reconnectTimer)
280→      this.reconnectTimer = null
281→    }
282→    this.ws?.close()
283→    this.ws = null
284→  }
285→
286→  onTasksChanged(callback: (data: { cwd: string }) => void): () => void {
287→    this.wsCallbacks.add(callback)
288→    return () => { this.wsCallbacks.delete(callback) }
289→  }
290→}
